const SETORES = [...new Set(RAW_DATA.map(r => r.setor))].sort((a,b)=>a-b);

const gapNum = (g) => {
  if (!g || g === "OK" || g === "") return null;
  const n = parseInt(g);
  return isNaN(n) ? null : n;
};

const Badge = ({ val }) => {
  if (!val || val === "#N/A") return <span className="text-gray-400">—</span>;
  if (val === "OK") return <span style={{color:"#16a34a",fontWeight:700}}>OK</span>;
  if (val === "0") return <span style={{color:"#dc2626"}}>0%</span>;
  if (/^\d+%$/.test(val)) return <span style={{color:"#b45309"}}>{val}</span>;
  return <span>{val}</span>;
};

const GapBadge = ({ gap }) => {
  const n = gapNum(gap);
  if (gap === "OK" || gap === "") return gap === "OK" ? <span style={{color:"#16a34a",fontWeight:700}}>OK</span> : <span className="text-gray-400">—</span>;
  if (n !== null && n < 0) return <span style={{color:"#dc2626",fontWeight:700}}>{n}</span>;
  return <span>{gap}</span>;
};

const OkBadge = ({ val }) => {
  if (!val || val === "#N/A" || val === "") return <span className="text-gray-400">—</span>;
  if (val === "OK") return <span style={{background:"#16a34a",color:"white",borderRadius:4,padding:"1px 7px",fontWeight:700,fontSize:12}}>OK</span>;
  if (val === "0") return <span style={{background:"#dc2626",color:"white",borderRadius:4,padding:"1px 7px",fontWeight:700,fontSize:12}}>0</span>;
  const n = parseInt(val);
  if (!isNaN(n)) {
    const color = n >= 60 ? "#16a34a" : n >= 30 ? "#d97706" : "#dc2626";
    return <span style={{background:color,color:"white",borderRadius:4,padding:"1px 7px",fontWeight:700,fontSize:12}}>{n}</span>;
  }
  return <span>{val}</span>;
};

export default function App() {
  const [setor, setSetor] = useState(121);
  const [search, setSearch] = useState("");
  const [visita, setVisita] = useState("TODOS");

  const DIAS = ["TODOS", "SEG", "TER", "QUA", "QUI", "SEX", "SAB"];
  const DIA_LABEL = { TODOS:"Todos", SEG:"Segunda", TER:"Terça", QUA:"Quarta", QUI:"Quinta", SEX:"Sexta", SAB:"Sábado" };

  const filtered = useMemo(() => {
    let data = RAW_DATA.filter(r => r.setor === setor);
    if (visita !== "TODOS") {
      data = data.filter(r => r.visita === visita);
    }
    if (search.trim()) {
      const s = search.toLowerCase();
      data = data.filter(r =>
        r.fantasia.toLowerCase().includes(s) ||
        String(r.codigo).includes(s)
      );
    }
    // Sort: negative gap first (biggest gap = worst), then OK, then empty
    data = [...data].sort((a, b) => {
      const ga = gapNum(a.gap);
      const gb = gapNum(b.gap);
      if (ga !== null && gb !== null) return ga - gb;
      if (ga !== null) return -1;
      if (gb !== null) return 1;
      return 0;
    });
    return data;
  }, [setor, search, visita]);

  const totalOk = filtered.filter(r => r.lojas_ok === "OK").length;
  const totalPdvs = filtered.length;
  const now = new Date().toLocaleString("pt-BR");

  return (
    <div style={{minHeight:"100vh",background:"#f1f5f9",fontFamily:"'Segoe UI',Arial,sans-serif"}}>
      {/* Header */}
      <div style={{background:"linear-gradient(135deg,#1e3a5f 0%,#2563eb 100%)",color:"white",padding:"18px 24px 14px"}}>
        <div style={{maxWidth:1400,margin:"0 auto"}}>
          <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:10}}>
            <div style={{background:"rgba(255,255,255,0.15)",borderRadius:8,padding:"6px 12px",fontWeight:800,fontSize:20,letterSpacing:1}}>
              🏪 Loja Ideal
            </div>
            <div style={{flex:1}}>
              <div style={{fontWeight:700,fontSize:18}}>Rota Completa — GAP ordenado do maior para o menor</div>
              <div style={{fontSize:12,opacity:.8}}>Gerado: {now}</div>
            </div>
          </div>

          {/* Controls */}
          <div style={{display:"flex",gap:12,flexWrap:"wrap",alignItems:"center"}}>
            <div>
              <label style={{fontSize:12,opacity:.8,display:"block",marginBottom:2}}>Setor</label>
              <select
                value={setor}
                onChange={e => setSetor(Number(e.target.value))}
                style={{padding:"6px 14px",borderRadius:6,border:"none",fontWeight:700,fontSize:15,cursor:"pointer",background:"white",color:"#1e3a5f"}}
              >
                {SETORES.map(s => <option key={s} value={s}>Setor {s}</option>)}
              </select>
            </div>
            <div style={{flex:1,maxWidth:240}}>
              <label style={{fontSize:12,opacity:.8,display:"block",marginBottom:2}}>Buscar PDV</label>
              <input
                value={search}
                onChange={e => setSearch(e.target.value)}
                placeholder="Nome ou código..."
                style={{width:"100%",padding:"6px 12px",borderRadius:6,border:"none",fontSize:14,boxSizing:"border-box"}}
              />
            </div>
            <div>
              <label style={{fontSize:12,opacity:.8,display:"block",marginBottom:2}}>Dia de Visita</label>
              <div style={{display:"flex",gap:4,flexWrap:"wrap"}}>
                {DIAS.map(d => (
                  <button
                    key={d}
                    onClick={() => setVisita(d)}
                    style={{
                      padding:"5px 10px",
                      borderRadius:6,
                      border:"none",
                      cursor:"pointer",
                      fontWeight:700,
                      fontSize:12,
                      transition:"all .15s",
                      background: visita === d ? "white" : "rgba(255,255,255,0.18)",
                      color: visita === d ? "#1e3a5f" : "white",
                      boxShadow: visita === d ? "0 2px 6px rgba(0,0,0,.2)" : "none",
                    }}
                  >
                    {d === "TODOS" ? "Todos" : d}
                  </button>
                ))}
              </div>
            </div>
            <div style={{display:"flex",gap:16,marginLeft:"auto",flexWrap:"wrap"}}>
              <div style={{background:"rgba(255,255,255,.15)",borderRadius:8,padding:"8px 16px",textAlign:"center"}}>
                <div style={{fontWeight:800,fontSize:22}}>{totalPdvs}</div>
                <div style={{fontSize:11,opacity:.8}}>PDVs</div>
              </div>
              <div style={{background:"rgba(22,163,74,.3)",border:"1px solid rgba(22,163,74,.6)",borderRadius:8,padding:"8px 16px",textAlign:"center"}}>
                <div style={{fontWeight:800,fontSize:22}}>{totalOk}</div>
                <div style={{fontSize:11,opacity:.8}}>Loja Ideal OK</div>
              </div>
              <div style={{background:"rgba(220,38,38,.25)",border:"1px solid rgba(220,38,38,.5)",borderRadius:8,padding:"8px 16px",textAlign:"center"}}>
                <div style={{fontWeight:800,fontSize:22}}>{totalPdvs - totalOk}</div>
                <div style={{fontSize:11,opacity:.8}}>Com GAP</div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Table */}
      <div style={{maxWidth:1400,margin:"18px auto",padding:"0 12px"}}>
        <div style={{background:"white",borderRadius:10,boxShadow:"0 2px 12px rgba(0,0,0,.08)",overflow:"hidden"}}>
          <div style={{overflowX:"auto"}}>
            <table style={{width:"100%",borderCollapse:"collapse",fontSize:13}}>
              <thead>
                <tr style={{background:"#1e3a5f",color:"white"}}>
                  <th style={{padding:"10px 8px",textAlign:"left",fontWeight:700,whiteSpace:"nowrap"}}>Código</th>
                  <th style={{padding:"10px 8px",textAlign:"left",fontWeight:700}}>Fantasia</th>
                  <th style={{padding:"10px 8px",textAlign:"center",fontWeight:700}}>Visita</th>
                  <th style={{padding:"10px 8px",textAlign:"center",fontWeight:700}}>Sort Meta</th>
                  <th style={{padding:"10px 8px",textAlign:"center",fontWeight:700}}>Sort Real</th>
                  <th style={{padding:"10px 8px",textAlign:"center",fontWeight:700,background:"#dc2626"}}>Gap Sort</th>
                  <th style={{padding:"10px 8px",textAlign:"center",fontWeight:700}}>Exec Meta</th>
                  <th style={{padding:"10px 8px",textAlign:"center",fontWeight:700}}>Exec Real</th>
                  <th style={{padding:"10px 8px",textAlign:"center",fontWeight:700}}>Desaf Meta</th>
                  <th style={{padding:"10px 8px",textAlign:"center",fontWeight:700}}>Desaf Real</th>
                  <th style={{padding:"10px 8px",textAlign:"center",fontWeight:700}}>Desaf Gap</th>
                  <th style={{padding:"10px 8px",textAlign:"center",fontWeight:700,background:"#16a34a"}}>Loja OK</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((r, i) => {
                  const isOk = r.lojas_ok === "OK";
                  const hasGap = gapNum(r.gap) !== null && gapNum(r.gap) < 0;
                  const rowBg = isOk ? "#f0fdf4" : hasGap ? "#fef2f2" : i % 2 === 0 ? "#fff" : "#f8fafc";
                  return (
                    <tr key={r.codigo} style={{background:rowBg,borderBottom:"1px solid #e2e8f0"}}>
                      <td style={{padding:"7px 8px",fontWeight:600,color:"#64748b",fontSize:12}}>{r.codigo}</td>
                      <td style={{padding:"7px 8px",fontWeight:isOk?700:500,color:isOk?"#15803d":"#1e293b",maxWidth:180}}>{r.fantasia}</td>
                      <td style={{padding:"7px 8px",textAlign:"center"}}>
                        <span style={{background:"#e0e7ff",color:"#3730a3",borderRadius:4,padding:"1px 6px",fontSize:11,fontWeight:600}}>{r.visita}</span>
                      </td>
                      <td style={{padding:"7px 8px",textAlign:"center",color:"#475569"}}>{r.sort_meta || "—"}</td>
                      <td style={{padding:"7px 8px",textAlign:"center",fontWeight:600}}>{r.sort_real !== undefined ? r.sort_real : "—"}</td>
                      <td style={{padding:"7px 8px",textAlign:"center",fontWeight:700}}>
                        <GapBadge gap={r.gap} />
                      </td>
                      <td style={{padding:"7px 8px",textAlign:"center",color:"#475569",fontSize:12}}>{r.exec_meta || "—"}</td>
                      <td style={{padding:"7px 8px",textAlign:"center"}}>
                        <Badge val={r.exec_real} />
                      </td>
                      <td style={{padding:"7px 8px",textAlign:"center",color:"#475569",fontSize:12}}>{r.desaf_meta || "—"}</td>
                      <td style={{padding:"7px 8px",textAlign:"center",color:"#374151"}}>{r.desaf_real || "—"}</td>
                      <td style={{padding:"7px 8px",textAlign:"center"}}>
                        <Badge val={r.desaf_gap} />
                      </td>
                      <td style={{padding:"7px 8px",textAlign:"center"}}>
                        <OkBadge val={r.lojas_ok} />
                      </td>
                    </tr>
                  );
                })}
                {filtered.length === 0 && (
                  <tr><td colSpan={12} style={{textAlign:"center",padding:32,color:"#94a3b8"}}>Nenhum PDV encontrado.</td></tr>
                )}
              </tbody>
            </table>
          </div>
          <div style={{padding:"10px 16px",background:"#f8fafc",borderTop:"1px solid #e2e8f0",fontSize:12,color:"#64748b",display:"flex",gap:24}}>
            <span>Setor <strong>{setor}</strong>{visita !== "TODOS" ? <> | <strong>{DIA_LABEL[visita]}</strong></> : ""} | <strong>{totalPdvs}</strong> PDVs | <strong style={{color:"#16a34a"}}>{totalOk} OK</strong> | <strong style={{color:"#dc2626"}}>{totalPdvs - totalOk} com GAP</strong></span>
            <span style={{marginLeft:"auto"}}>🟢 Verde = Loja Ideal OK &nbsp; 🔴 Vermelho = GAP negativo</span>
          </div>
        </div>
      </div>
    </div>
  );
}